import React, { useEffect, useState } from "react";
import { Table, Button, Select, Tooltip } from "antd";
import { useDispatch, useSelector } from "react-redux";
import {
  ExternalLink,
  CheckCircle2,
  Clock,
  Truck,
  Package,
  Calendar,
  Layers,
  Search,
  User,
  Activity,
  DollarSign,
  ShoppingBag,
} from "lucide-react";
import { Link } from "react-router-dom";
import { config } from "../utils/axiosconfig";
import { getOrders, updateAOrder } from "../features/auth/authSlice";

const statusConfig = {
  Ordered: { color: "#3b82f6", icon: <Clock size={16} />, label: "Received" },
  Processed: {
    color: "#f59e0b",
    icon: <Activity size={16} />,
    label: "Preparing",
  },
  Shipped: { color: "#8b5cf6", icon: <Package size={16} />, label: "Shipped" },
  "Out for Delivery": {
    color: "#06b6d4",
    icon: <Truck size={16} />,
    label: "En Route",
  },
  Delivered: {
    color: "#10b981",
    icon: <CheckCircle2 size={16} />,
    label: "Delivered",
  },
};

const Orders = () => {
  const dispatch = useDispatch();
  const [loadingOrder, setLoadingOrder] = useState(null);
  const [searchText, setSearchText] = useState("");

  useEffect(() => {
    dispatch(getOrders(config));
  }, [dispatch]);

  const orderState = useSelector((state) => state?.auth?.orders.orders);

  const updateOrderStatus = (id, status) => {
    setLoadingOrder(id);
    dispatch(updateAOrder({ id, status })).finally(() => setLoadingOrder(null));
  };

  const columns = [
    {
      title: "Order Index",
      dataIndex: "id",
      render: (text) => (
        <span className="font-black text-[11px] text-slate-400 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100 uppercase tracking-widest">
          #ORD-{text?.slice(-6).toUpperCase()}
        </span>
      ),
    },
    {
      title: "Customer Profile",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-blue-50 border border-blue-100 flex items-center justify-center text-blue-600 shadow-sm shadow-blue-500/10">
            <User size={22} />
          </div>
          <div className="flex flex-col">
            <span className="font-black text-slate-900 text-[16px] tracking-tight leading-none mb-1.5">
              {text}
            </span>
            <span className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">
              Verified Patient
            </span>
          </div>
        </div>
      ),
    },
    {
      title: "Dispatch Date",
      dataIndex: "date",
      render: (text) => (
        <div className="flex flex-col">
          <div className="flex items-center gap-2 text-slate-900 font-black text-[14px]">
            <Calendar size={14} className="text-blue-600" />
            {text.split(",")[0]}
          </div>
          <span className="text-slate-400 text-[11px] font-bold uppercase tracking-widest mt-1 ml-5">
            {text.split(",")[1]}
          </span>
        </div>
      ),
    },
    {
      title: "Financial Value",
      dataIndex: "amount",
      render: (text) => (
        <div className="flex items-center gap-2">
          <div className="p-2 bg-emerald-50 text-emerald-600 rounded-xl">
             <DollarSign size={16} />
          </div>
          <div className="flex items-baseline gap-1">
            <span className="font-black text-slate-900 text-[18px]">
              {Number(text).toLocaleString()}
            </span>
            <span className="text-[11px] text-slate-400 font-black uppercase tracking-widest">
              ETB
            </span>
          </div>
        </div>
      ),
    },
    {
      title: "Logistics Status",
      dataIndex: "status",
      render: (status) => {
        const conf = statusConfig[status] || statusConfig["Ordered"];
        return (
          <div
            className="flex items-center gap-2.5 px-4 py-2 rounded-2xl border w-fit shadow-sm"
            style={{
              backgroundColor: `${conf.color}08`,
              borderColor: `${conf.color}15`,
              color: conf.color,
            }}
          >
            <div className="flex items-center justify-center animate-in zoom-in-0 duration-500">
               {conf.icon}
            </div>
            <span className="text-[11px] font-black uppercase tracking-[0.1em]">
              {conf.label}
            </span>
          </div>
        );
      },
    },
    {
      title: "Terminal Control",
      dataIndex: "action",
      width: 200,
      render: (_, record) => (
        <div className="flex items-center gap-3">
          <Select
            defaultValue={record.status}
            disabled={loadingOrder === record.orderId}
            onSelect={(value) => updateOrderStatus(record.orderId, value)}
            className="modern-select-premium flex-1 h-12"
            bordered={false}
          >
            <Select.Option value="Ordered"><span className="font-bold text-slate-600">Received</span></Select.Option>
            <Select.Option value="Processed"><span className="font-bold text-slate-600">Preparing</span></Select.Option>
            <Select.Option value="Shipped"><span className="font-bold text-slate-600">Shipped</span></Select.Option>
            <Select.Option value="Out for Delivery"><span className="font-bold text-slate-600">In Delivery</span></Select.Option>
            <Select.Option value="Delivered"><span className="font-bold text-slate-600">Completed</span></Select.Option>
          </Select>
          <Tooltip title="Deep Inspect">
            <Link to={`/admin/order/${record.orderId}`}>
              <Button
                type="text"
                icon={<ExternalLink size={18} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-2xl h-12 w-12 flex items-center justify-center border border-slate-100 shadow-sm transition-all"
              />
            </Link>
          </Tooltip>
        </div>
      ),
    },
  ];

  const data1 =
    orderState?.map((order, i) => {
      const firstName = order?.user?.firstname || order?.firstName || "";
      const lastName = order?.user?.lastname || order?.lastName || "";
      const fullName = (firstName + " " + lastName).trim();

      return {
        key: order?.id || order?._id || i,
        id: order?.id || order?._id,
        orderId: order?.id || order?._id,
        name: fullName || "Guest Customer",
        amount: order?.totalPrice || 0,
        date: new Date(order?.createdAt).toLocaleString(),
        status: order?.status || order?.orderStatus || "Ordered",
      };
    }) || [];


  const filteredData = data1.filter(
    (o) =>
      o.name.toLowerCase().includes(searchText.toLowerCase()) ||
      o.id.toLowerCase().includes(searchText.toLowerCase()),
  );

  const totalRevenue = data1.reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-10 pb-20 animate-in fade-in duration-500">
      {/* Page Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
        <div className="space-y-1">
          <div className="flex items-center gap-2 mb-2">
            <div className="h-1 w-6 bg-blue-600 rounded-full" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-widest">Supply Chain Monitor</span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">
             Logistics Vault<span className="text-blue-600">.</span>
          </h1>
          <p className="text-[15px] text-slate-400 font-bold max-w-lg">
             Monitor pharmaceutical distribution and fulfill clinical orders globally.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-6 w-full lg:w-auto">
          <div className="flex items-center gap-5 bg-white p-4 px-8 rounded-[32px] border border-slate-100 shadow-2xl shadow-slate-200/40 w-full sm:w-auto overflow-hidden relative group">
            <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:scale-110 transition-transform duration-1000">
               <ShoppingBag size={80} />
            </div>
            <div className="p-3 bg-blue-600 text-white rounded-2xl shadow-lg shadow-blue-500/20 z-10">
              <DollarSign size={24} />
            </div>
            <div className="z-10">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">
                 Accumulated Value
              </p>
              <p className="text-[24px] font-black text-slate-900 leading-none">
                {totalRevenue.toLocaleString()}{" "}
                <span className="text-[12px] text-blue-600 uppercase tracking-widest">ETB</span>
              </p>
            </div>
          </div>

          <div className="relative w-full sm:w-80 group">
            <Search
              className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors"
              size={18}
            />
            <input
              type="text"
              placeholder="Search by ID or name..."
              className="pl-12 pr-6 h-14 w-full bg-white border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-200 text-[14px] font-bold text-slate-900 shadow-sm transition-all"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
        </div>
      </div>

      <div className="enterprise-card bg-white p-0 overflow-hidden border border-slate-100 shadow-xl shadow-slate-200/20">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between p-8 border-b border-slate-50 bg-slate-50/30 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-slate-900 text-white rounded-2xl shadow-lg">
              <ShoppingBag size={20} />
            </div>
            <div>
              <h3 className="text-[18px] font-black text-slate-900 leading-none">Active Transactions</h3>
              <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-wider">
                 Register Index: <span className="text-blue-600">{filteredData.length} records</span>
              </p>
            </div>
          </div>
          <div className="flex items-center gap-6">
             <div className="flex flex-col text-right">
                <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-1">Terminal Status</span>
                <span className="text-[12px] font-black text-emerald-500 flex items-center gap-1.5 justify-end">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                   Fully Optimized
                </span>
             </div>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={filteredData}
          pagination={{
            pageSize: 10,
            className: "px-8 py-6",
            position: ["bottomRight"]
          }}
          className="enterprise-table"
        />
      </div>

      <style>{`
        .modern-select-premium .ant-select-selector {
          background: #f8fafc !important;
          border-radius: 18px !important;
          border: 1px solid #f1f5f9 !important;
          padding: 0 20px !important;
          height: 48px !important;
          display: flex !important;
          align-items: center !important;
          box-shadow: inset 0 2px 4px 0 rgba(0, 0, 0, 0.01) !important;
        }
      `}</style>
    </div>
  );
};

export default Orders;
